	oldsize = GET_SIZE(HDRP(ptr)) - DSIZE;
	if (size < oldsize)
		oldsize = size;
	memcpy(newptr, ptr, oldsize);

	/* Free the old block. */
	mm_free(ptr);

	return (newptr);
